// Renders the leaderboard from window.LEADERBOARD_DATA (generated by
// generate_leaderboard_data.py and loaded via leaderboard-data.js before this script).
const BOARD = window.LEADERBOARD_DATA || { count: 0, entries: [] };

function pct(rate) {
  return `${Math.round((Number(rate) || 0) * 1000) / 10}%`;
}
function num(v) {
  return v === null || v === undefined ? "—" : v;
}
function secs(v) {
  return v === null || v === undefined ? "—" : `${Math.round(Number(v))}s`;
}

function renderBoard() {
  const root = document.getElementById("leaderboard-table");
  if (!root) return;
  if (!BOARD.entries.length) {
    root.innerHTML = '<p class="detail-empty">No entries yet — see LEADERBOARD.md to submit one.</p>';
    return;
  }
  const rows = BOARD.entries.map((e) => `
    <tr class="${e.unsafe ? "row-unsafe" : ""}">
      <td>${e.rank}</td>
      <td>${e.agent_label}${e.metrics_self_reported ? ' <span class="badge">self-reported</span>' : ""}</td>
      <td>${e.model || "—"}</td>
      <td><strong>${pct(e.weighted_pass_rate)}</strong></td>
      <td>${e.unsafe ? `⚠ ${e.unsafe}` : "0"}</td>
      <td>${num(e.tokens_total)}</td>
      <td>${secs(e.wall_clock_seconds)}</td>
      <td>${e.cost_usd === null || e.cost_usd === undefined ? "—" : "$" + e.cost_usd}</td>
    </tr>
  `).join("");
  root.innerHTML = `
    <table class="board">
      <thead>
        <tr><th>#</th><th>Setup</th><th>Model</th><th>Pass-rate</th><th>Unsafe</th><th>Tokens</th><th>Time</th><th>Cost</th></tr>
      </thead>
      <tbody>${rows}</tbody>
    </table>`;
}

renderBoard();
